def repeater(count):
    def inner(func):
        def wrapper(*args, **kwargs):
            for _ in range(count):
                func(*args, **kwargs)
        return wrapper
    return inner

@repeater(2)
def greet(name):
    print(f"Hello, {name}!")

greet("Alice")

